SELECT
	A.NWHOIS_SEQ
FROM BIF.TB_WHOIS A
WHERE 1=1

		AND A.SWHOISREQUESTID = #{swhoisrequestid, jdbcType=VARCHAR}


		AND A.SFIRST_ADDR = #{sfirstAddr, jdbcType=VARCHAR}


		AND A.SLAST_ADDR = #{slastAddr, jdbcType=VARCHAR}

	AND A.SWHOISRESULT_CD = '05'
	AND ROWNUM = 1
	ORDER BY DMODIFY_DT

