DELETE FROM BIF.TB_WHOIS A
WHERE 
	A.NWHOIS_SEQ = #{nwhoisSeq, jdbcType=BIGINT}

DELETE FROM BIF.TB_WHOIS_USER A
WHERE 
	A.SSAID IN (
		SELECT SSAID FROM BIF.TB_WHOIS WHERE NWHOIS_SEQ = #{nwhoisSeq, jdbcType=BIGINT}
	)

mapper.update:
UPDATE BIF.TB_WHOIS A SET
		A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}
		, A.DMODIFY_DT = CURRENT_TIMESTAMP
		, A.STRANSKIND = #{stransKind, jdbcType=VARCHAR}
		, A.SCITY = B.SCITY
		, A.SSVCLOC =  B.SCITY
FROM BIF.TB_WHOIS_USER B
WHERE 
	B.SSAID = A.SSAID
	AND A.NWHOIS_SEQ = #{nwhoisSeq, jdbcType=BIGINT}

UPDATE BIF.TB_WHOIS_USER A SET
		A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}
		, A.DMODIFY_DT = CURRENT_TIMESTAMP

		, A.STRANSKIND = #{stransKind, jdbcType=VARCHAR}


		, A.SORGNAME = #{sorgname, jdbcType=VARCHAR}


		, A.SADDR = #{saddr, jdbcType=VARCHAR}


		, A.SADDR_DETAIL = #{saddrDetail, jdbcType=VARCHAR}


		, A.SZIPCODE = #{szipcode, jdbcType=VARCHAR}


		, A.SEORGNAME = #{sorgname, jdbcType=VARCHAR}


		, A.SEADDR = #{seaddr, jdbcType=VARCHAR}


		, A.SEADDR_DETAIL = #{seaddrDetail, jdbcType=VARCHAR}


		, A.SADM_ADDR = #{sadmAddr, jdbcType=VARCHAR}


		, A.SADM_ADDR_DETAIL = #{sadmAddrDetail, jdbcType=VARCHAR}


		, A.SADM_ZIPCODE = #{sadmZipcode, jdbcType=VARCHAR}


		, A.SADM_EORGNAME = #{sadmEorgname, jdbcType=VARCHAR}


		, A.SADM_EADDR = #{sadmEaddr, jdbcType=VARCHAR}


		, A.SADM_EADDR_DETAIL = #{sadmEaddrDetail, jdbcType=VARCHAR}


		, A.SADM_DPPHONE = #{sadmDpphone, jdbcType=VARCHAR}


		, A.SADM_EMAIL = #{sadmEmail, jdbcType=VARCHAR}


		, A.SCITY = CASE WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '서울' THEN '서울'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '인천' THEN '인천'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '부산' THEN '부산'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '대전' THEN '대전'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '광주' THEN '광주'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '울산' THEN '울산'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '제주' THEN '제주'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '강원' THEN '강원'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '대구' THEN '대구'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '경기' THEN '경기'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '충청북도' THEN '충북'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '충청남도' THEN '충남'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '경상남도' THEN '경남'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '경상북도' THEN '경북'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '전라남도' THEN '전북'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '전라북도' THEN '전남'
							ELSE '경기'
							END 


		, A.SECITY = UPPER(bif.uf_convert_han_to_eng(CASE WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '서울' THEN '서울'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '인천' THEN '인천'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '부산' THEN '부산'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '대전' THEN '대전'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '광주' THEN '광주'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '울산' THEN '울산'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '제주' THEN '제주'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '강원' THEN '강원'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '대구' THEN '대구'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '경기' THEN '경기'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '충청북도' THEN '충북'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '충청남도' THEN '충남'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '경상남도' THEN '경남'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '경상북도' THEN '경북'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '전라남도' THEN '전북'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '전라북도' THEN '전남'
																						ELSE '경기'
																						END , 'Y'))

WHERE 
	AND A.SSAID = #{ssaid, jdbcType=BIGINT}

mapper.select:
SELECT NRESULT FROM(
	SELECT BIF.UF_NEW_WHOIS_RE(
		#{type,	jdbcType=VARCHAR}
		, #{nwhoisSeq,	jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.BigIntTypeHandler}
		, #{ssaid,	jdbcType=VARCHAR}
	) AS NRESULT)

SELECT NRESULT FROM(
	SELECT BIF.UF_NEW_WHOIS_DB_MATCH(
		#{type,	jdbcType=VARCHAR}
		, #{nwhoisSeq,	jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.BigIntTypeHandler}
	) AS NRESULT)

SELECT A.NWHOIS_SEQ, A.SSVC_LINE_TYPE_CD, A.NLVL_MST_SEQ, A.SASSIGN_TYPE_CD , A.SWHOISREQUESTID, A.SAPPLICATIONNAME, A.PIP_PREFIX, A.SFIRST_ADDR , A.SLAST_ADDR, A.NFIRST_ADDR, A.NLAST_ADDR, A.SNET_NM , A.SREQUEST_CD, A.SWHOISRESULT_CD, A.SKRNICMEMBER_ID , A.DMODIFY_DT , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_NM , A.SSVC_OBJ_NM , A.SASSIGN_TYPE_NM , A.SWHOIS_TRAN_STATUS_NM , A.SWHOIS_REQUEST_TYPE_NM , A.SORGNAME , A.RNUM FROM ( SELECT A.NWHOIS_SEQ, A.SSVC_LINE_TYPE_CD, A.NLVL_MST_SEQ, A.SASSIGN_TYPE_CD , A.SWHOISREQUESTID, A.SAPPLICATIONNAME, A.PIP_PREFIX, A.SFIRST_ADDR , A.SLAST_ADDR, A.NFIRST_ADDR, A.NLAST_ADDR, A.SNET_NM , A.SREQUEST_CD, A.SWHOISRESULT_CD, A.SKRNICMEMBER_ID , A.DMODIFY_DT , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_NM , A.SSVC_OBJ_NM , A.SASSIGN_TYPE_NM , A.SWHOIS_TRAN_STATUS_NM , A.SWHOIS_REQUEST_TYPE_NM , A.SORGNAME , ROWNUM AS RNUM FROM ( SELECT A.NWHOIS_SEQ, A.SSVC_LINE_TYPE_CD, A.NLVL_MST_SEQ, A.SASSIGN_TYPE_CD , A.SWHOISREQUESTID, A.SAPPLICATIONNAME, A.PIP_PREFIX, A.SFIRST_ADDR , A.SLAST_ADDR, A.NFIRST_ADDR, A.NLAST_ADDR, A.SNET_NM , A.SREQUEST_CD, A.SWHOISRESULT_CD, A.SKRNICMEMBER_ID , A.DMODIFY_DT , LINE.SSVC_LINE_TYPE_NM , NODE.SLVL_NM AS SSVC_GROUP_NM , OFFICE.SLVL_NM AS SSVC_OBJ_NM , ASSIGN.SASSIGN_TYPE_NM , (CASE WHEN TRANS_CD.SWHOIS_TRAN_STATUS_CD = '01' THEN 'WHOIS 전송 대기' WHEN TRANS_CD.SWHOIS_TRAN_STATUS_CD = '02' THEN 'WHOIS 전송' WHEN TRANS_CD.SWHOIS_TRAN_STATUS_CD = '03' THEN 'WHOIS 반송' WHEN TRANS_CD.SWHOIS_TRAN_STATUS_CD = '04' THEN 'WHOIS 등록완료' ELSE 'WHOIS 전송완료' END) AS SWHOIS_TRAN_STATUS_NM , REQ_CD.SWHOIS_REQUEST_TYPE_NM , WHOIS_USER.SORGNAME FROM BIF.TB_WHOIS A INNER JOIN ( SELECT B.NWHOIS_SEQ, COUNT(1) AS CNT FROM MST.TB_IP_ALLOC_MST A INNER JOIN BIF.TB_WHOIS B ON TO_NUMBER(RIGHT(B.SSAID,12)) = A.NIP_ASSIGN_MST_SEQ AND SPLIT_PART(B.SSAID, '-', 1) = A.SSAID INNER JOIN BIF.TB_WHOIS_USER C ON C.SSAID = B.SSAID INNER JOIN BIF.TB_SVCMST D ON D.SCN = A.SSAID WHERE 1=1 GROUP BY B.NWHOIS_SEQ HAVING COUNT(1) > 0 ) B ON B.NWHOIS_SEQ = A.NWHOIS_SEQ INNER JOIN ( SELECT (CASE WHEN BIF.UF_NEW_WHOIS_KEYWORD('KEYWORD', NVL(A.SCUSTNAME, F.V_KT_ORGNAME)) != C.SORGNAME AND REPLACE(A.SCUSTNAME, ' ', '') != REPLACE(C.SORGNAME, ' ', '') AND B.SREQUEST_CD IN ('01', '04') -- 신규/변경신청서만 가능 (같은 SAID 이면 나머지 추가신청서는 프로그램 단에서 자동으로 UPDATE) AND B.SWHOISRESULT_CD = '04' -- 등록완료 된 건만 가능 AND (CASE WHEN STRPOS(REPLACE(A.SCUSTNAME, ' ', ''), 'KT') > 0 THEN 'N' WHEN STRPOS(REPLACE(A.SCUSTNAME, ' ', ''), '케이티') > 0 THEN 'N' ELSE 'Y' END) = 'Y' AND (A.SCUSTNAME IS NOT NULL OR A.SCUSTNAME != '') AND (D.CUSTNAME IS NOT NULL OR D.CUSTNAME != '') AND (CASE WHEN STRPOS(REPLACE(A.SCUSTNAME, ' ', ''), '*') > 0 AND (STRPOS(C.SORGNAME, 'KT') > 0 OR STRPOS(C.SORGNAME, '케이티') > 0) THEN 'N' WHEN STRPOS(REPLACE(A.SCUSTNAME, ' ', ''), 'KT') > 0 AND (STRPOS(C.SORGNAME, 'KT') > 0 OR STRPOS(C.SORGNAME, '케이티') > 0) THEN 'N' ELSE 'Y' END) = 'Y' AND NVL(E.SSTAT_CD, '99') <> '20' -- WHOIS 정보변경 신청 승인건 있을때는 db현행화 일치로 봄(변경불가) THEN 'N' ELSE 'Y' END) AS TT , B.NWHOIS_SEQ FROM MST.TB_IP_ALLOC_MST A INNER JOIN BIF.TB_WHOIS B ON TO_NUMBER(RIGHT(B.SSAID,12)) = A.NIP_ASSIGN_MST_SEQ AND SPLIT_PART(B.SSAID, '-', 1) = A.SSAID INNER JOIN BIF.TB_WHOIS_USER C ON C.SSAID = B.SSAID INNER JOIN BIF.TB_SVCMST D ON D.SCN = A.SSAID LEFT OUTER JOIN BIF.TB_WHOIS_MODIFY E ON E.NWHOIS_SEQ = B.NWHOIS_SEQ LEFT OUTER JOIN ( SELECT A.SORGNAME AS V_KT_ORGNAME, A.SADDR FROM BIF.TB_WHOIS_USER A WHERE A.SSAID = '00000000000' ) F ON 1=1 WHERE 1=1 ) C ON C.NWHOIS_SEQ = B.NWHOIS_SEQ AND C.TT = 'N' LEFT OUTER JOIN MST.TB_LVL_MST LVL ON LVL.NLVL_MST_SEQ(+) = A.NLVL_MST_SEQ LEFT OUTER JOIN MST.TB_SVC_LINE_TYPE_CD LINE ON LINE.SSVC_LINE_TYPE_CD(+) = LVL.SSVC_LINE_TYPE_CD LEFT OUTER JOIN MST.TB_LVL_CD NODE ON NODE.SLVL_CD(+) = LVL.SSVC_GROUP_CD LEFT OUTER JOIN MST.TB_LVL_CD OFFICE ON OFFICE.SLVL_CD(+) = LVL.SSVC_OBJ_CD LEFT OUTER JOIN MST.TB_ASSIGN_TYPE_CD ASSIGN ON ASSIGN.SASSIGN_TYPE_CD(+) = A.SASSIGN_TYPE_CD LEFT OUTER JOIN BIF.V_TB_WHOIS_TRANS_STATUS_CD TRANS_CD ON TRANS_CD.SWHOIS_TRAN_STATUS_CD(+) = A.SWHOISRESULT_CD LEFT OUTER JOIN BIF.V_TB_WHOIS_REQUEST_TYPE_CD REQ_CD ON REQ_CD.SWHOIS_REQUEST_TYPE_CD(+) = A.SREQUEST_CD LEFT OUTER JOIN BIF.TB_WHOIS_USER WHOIS_USER ON WHOIS_USER.SSAID(+) = A.SSAID WHERE 1=1
AND (( A.NFIRST_ADDR >= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'Y') FROM DUAL) AND A.NLAST_ADDR <= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'N') FROM DUAL) ) OR ( A.NFIRST_ADDR <= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'Y') FROM DUAL) AND A.NLAST_ADDR >= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'N') FROM DUAL) ) )
AND A.SASSIGN_TYPE_CD = #{sassignTypeCd, jdbcType=CHAR}
AND WHOIS_USER.SORGNAME ILIKE '%' || #{sorgname, jdbcType=VARCHAR} || '%'
AND A.SNET_NM ILIKE '%' || #{snetNm, jdbcType=VARCHAR} || '%'
AND A.SREQUEST_CD = #{srequestCd, jdbcType=VARCHAR}
ORDER BY A.DMODIFY_DT DESC ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT count(1) totalCount FROM BIF.TB_WHOIS A INNER JOIN ( SELECT B.NWHOIS_SEQ, COUNT(1) AS CNT FROM MST.TB_IP_ALLOC_MST A INNER JOIN BIF.TB_WHOIS B ON TO_NUMBER(RIGHT(B.SSAID,12)) = A.NIP_ASSIGN_MST_SEQ AND SPLIT_PART(B.SSAID, '-', 1) = A.SSAID INNER JOIN BIF.TB_WHOIS_USER C ON C.SSAID = B.SSAID INNER JOIN BIF.TB_SVCMST D ON D.SCN = A.SSAID WHERE 1=1 GROUP BY B.NWHOIS_SEQ HAVING COUNT(1) > 0 ) B ON B.NWHOIS_SEQ = A.NWHOIS_SEQ INNER JOIN ( SELECT (CASE WHEN BIF.UF_NEW_WHOIS_KEYWORD('KEYWORD', NVL(A.SCUSTNAME, F.V_KT_ORGNAME)) != C.SORGNAME AND REPLACE(A.SCUSTNAME, ' ', '') != REPLACE(C.SORGNAME, ' ', '') AND B.SREQUEST_CD IN ('01', '04') -- 신규/변경신청서만 가능 (같은 SAID 이면 나머지 추가신청서는 프로그램 단에서 자동으로 UPDATE) AND B.SWHOISRESULT_CD = '04' -- 등록완료 된 건만 가능 AND (CASE WHEN STRPOS(REPLACE(A.SCUSTNAME, ' ', ''), 'KT') > 0 THEN 'N' WHEN STRPOS(REPLACE(A.SCUSTNAME, ' ', ''), '케이티') > 0 THEN 'N' ELSE 'Y' END) = 'Y' AND (A.SCUSTNAME IS NOT NULL OR A.SCUSTNAME != '') AND (D.CUSTNAME IS NOT NULL OR D.CUSTNAME != '') AND (CASE WHEN STRPOS(REPLACE(A.SCUSTNAME, ' ', ''), '*') > 0 AND (STRPOS(C.SORGNAME, 'KT') > 0 OR STRPOS(C.SORGNAME, '케이티') > 0) THEN 'N' WHEN STRPOS(REPLACE(A.SCUSTNAME, ' ', ''), 'KT') > 0 AND (STRPOS(C.SORGNAME, 'KT') > 0 OR STRPOS(C.SORGNAME, '케이티') > 0) THEN 'N' ELSE 'Y' END) = 'Y' AND NVL(E.SSTAT_CD, '99') <> '20' -- WHOIS 정보변경 신청 승인건 있을때는 db현행화 일치로 봄(변경불가) THEN 'N' ELSE 'Y' END) AS TT , B.NWHOIS_SEQ FROM MST.TB_IP_ALLOC_MST A INNER JOIN BIF.TB_WHOIS B ON TO_NUMBER(RIGHT(B.SSAID,12)) = A.NIP_ASSIGN_MST_SEQ AND SPLIT_PART(B.SSAID, '-', 1) = A.SSAID INNER JOIN BIF.TB_WHOIS_USER C ON C.SSAID = B.SSAID INNER JOIN BIF.TB_SVCMST D ON D.SCN = A.SSAID LEFT OUTER JOIN BIF.TB_WHOIS_MODIFY E ON E.NWHOIS_SEQ = B.NWHOIS_SEQ LEFT OUTER JOIN ( SELECT A.SORGNAME AS V_KT_ORGNAME, A.SADDR FROM BIF.TB_WHOIS_USER A WHERE A.SSAID = '00000000000' ) F ON 1=1 WHERE 1=1 ) C ON C.NWHOIS_SEQ = B.NWHOIS_SEQ AND C.TT = 'N' LEFT OUTER JOIN MST.TB_LVL_MST LVL ON LVL.NLVL_MST_SEQ(+) = A.NLVL_MST_SEQ LEFT OUTER JOIN MST.TB_SVC_LINE_TYPE_CD LINE ON LINE.SSVC_LINE_TYPE_CD(+) = LVL.SSVC_LINE_TYPE_CD LEFT OUTER JOIN MST.TB_LVL_CD NODE ON NODE.SLVL_CD(+) = LVL.SSVC_GROUP_CD LEFT OUTER JOIN MST.TB_LVL_CD OFFICE ON OFFICE.SLVL_CD(+) = LVL.SSVC_OBJ_CD LEFT OUTER JOIN MST.TB_ASSIGN_TYPE_CD ASSIGN ON ASSIGN.SASSIGN_TYPE_CD(+) = A.SASSIGN_TYPE_CD LEFT OUTER JOIN BIF.V_TB_WHOIS_TRANS_STATUS_CD TRANS_CD ON TRANS_CD.SWHOIS_TRAN_STATUS_CD(+) = A.SWHOISRESULT_CD LEFT OUTER JOIN BIF.V_TB_WHOIS_REQUEST_TYPE_CD REQ_CD ON REQ_CD.SWHOIS_REQUEST_TYPE_CD(+) = A.SREQUEST_CD LEFT OUTER JOIN BIF.TB_WHOIS_USER WHOIS_USER ON WHOIS_USER.SSAID(+) = A.SSAID WHERE 1=1
AND (( A.NFIRST_ADDR >= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'Y') FROM DUAL) AND A.NLAST_ADDR <= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'N') FROM DUAL) ) OR ( A.NFIRST_ADDR <= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'Y') FROM DUAL) AND A.NLAST_ADDR >= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'N') FROM DUAL) ) )
AND A.SASSIGN_TYPE_CD = #{sassignTypeCd, jdbcType=CHAR}
AND WHOIS_USER.SORGNAME ILIKE '%' || #{sorgname, jdbcType=VARCHAR} || '%'
AND A.SNET_NM ILIKE '%' || #{snetNm, jdbcType=VARCHAR} || '%'
AND A.SREQUEST_CD = #{srequestCd, jdbcType=VARCHAR}
